// Rotierende Slogans - bei jedem Versand kommt der jeweils nächste dran
const slogans = [
  'Eine süße Überraschung für Ihr Team – EisFavorite kommt zu Ihnen!',
  'Motivation, die schmilzt: Eis für Ihre Mitarbeiter als Dankeschön.',
  'Sommer im Büro: Der Eiswagen direkt vor Ihrer Tür.',
  'Zeigen Sie Ihrem Team Wertschätzung – mit einer Portion Eis.',
  'Kleine Geste, große Wirkung: Eis für alle Mitarbeiter.',
  'Der Eiswagen für Firmenfeiern, Jubiläen & Dankeschön-Aktionen.',
  'Lassen Sie Ihr Team schlecken statt schwitzen – EisFavorite ist da!',
  'Frisches Eis, glückliche Gesichter: Die perfekte Pause für Ihr Team.'
];

const now = Date.now();
const fourWeeksMs = 28 * 24 * 60 * 60 * 1000;

const toContact = $input.all()
  .map(item => item.json)
  .filter(lead => {
    // Nur Leads mit E-Mail
    if (!lead.email) return false;

    // Gebuchte oder abgelehnte Firmen nicht mehr anschreiben
    if (lead.status === 'gebucht' || lead.status === 'abgelehnt') return false;

    // Noch nie kontaktiert -> sofort dran
    if (!lead.lastContactedAt) return true;

    // Sonst: nur wenn letzter Kontakt >= 4 Wochen her
    const lastMs = new Date(lead.lastContactedAt).getTime();
    return (now - lastMs) >= fourWeeksMs;
  })
  .map(lead => {
    const sloganIndex = lead.sloganIndex || 0;
    const slogan = slogans[sloganIndex % slogans.length];
    return {
      json: {
        ...lead,
        slogan,
        nextSloganIndex: sloganIndex + 1
      }
    };
  });

console.log(`📢 ${toContact.length} Firmen werden heute kontaktiert`);
return toContact;
